 var(--border-light);\\n}\\n\\n.hero-eyebrow {\\n  font-size: 12px;\\n  font-weight: 500;\\n  letter-spacing: 0.10em;\\n  text-transform: uppercase;\\n  color: var(--text-tertiary);\\n  margin-bottom: 0.75rem;\\n}\\n\\n.hero-title {\\n  font-family: \'Noto Serif KR\', serif;\\n  font-size: 24px;\\n  font-weight: 500;\\n  color: var(--text-primary);\\n  margin-bottom: 1rem;\\n  line-height: 1.4;\\n}\\n\\n.hero-desc {\\n  font-size: 15px;\\n  color: var(--text-secondary);\\n  line-height: 1.7;\\n}\\n\\n.steps { display: flex; flex-direction: column; gap: 1px; }\\n\\n.step {\\n  display: flex;\\n  gap: 16px;\\n  align-items: flex-start;\\n  padding: 1.25rem;\\n  background: var(--bg-primary);\\n  border: 0.5px solid var(--border-light);\\n}\\n.step:first-child { border-radius: var(--radius-md) var(--radius-md) 0 0; }\\n.step:last-child  { border-radius: 0 0 var(--radius-md) var(--radius-md); }\\n\\n.step-num {\\n  flex-shrink: 0;\\n  width: 28px;\\n  height: 28px;\\n  border-radius: 50%;\\n  background: var(--bg-secondary);\\n  border: 0.5px solid var(--border-medium);\\n  display: flex;\\n  align-items: center;\\n  justify-content: center;\\n  font-size: 13px;\\n  font-weight: 500;\\n  color: var(--text-secondary);\\n  margin-top: 2px;\\n}\\n\\n.step-title {\\n  font-size: 15px;\\n  font-weight: 500;\\n  color: var(--text-primary);\\n  margin-bottom: 4px;\\n}\\n\\n.step-desc {\\n  font-size: 14px;\\n  color: var(--text-secondary);\\n  line-height: 1.6;\\n}\\n\\n.cta-card {\\n  margin-top: 1.5rem;\\n  border-radius: var(--radius-lg);\\n  border: 0.5px solid var(--border-medium);\\n  background: var(--bg-primary);\\n  padding: 1.5rem 1.5rem 1.25rem;\\n}\\n\\n.cta-label {\\n  font-size: 12px;\\n  font-weight: 500;\\n  text-transform: uppercase;\\n  letter-spacing: 0.08em;\\n  color: var(--text-tertiary);\\n  margin-bottom: 8px;\\n}\\n\\n.cta-text {\\n  font-size: 15px;\\n  color: var(--text-primary);\\n  line-height: 1.6;\\n  margin-bottom: 6px;\\n}\\n\\n.cta-sub {\\n  font-size: 14px;\\n  color: var(--text-secondary);\\n  line-height: 1.6;\\n}\\n\\n@media (max-width: 600px) {\\n  .hero { padding: 1.5rem 1.25rem; }\\n  .hero-title { font-size: 20px; }\\n  .step { padding: 1rem; }\\n  .cta-card { padding: 1.25rem 1rem; }\\n}\",\"custom_js\":\"\"}',1,'2026-03-13 09:34:40','2026-03-13 09:34:40'),(88,'home',6,3,'{\"btn_url\":\"\\/booking\",\"bg_color\":\"#1e40af\"}',1,'2026-03-13 09:34:40','2026-03-13 09:34:40'),(89,'home',3,4,'{\"count\":6,\"show_price\":1,\"show_duration\":1}',1,'2026-03-13 09:34:40','2026-03-13 09:34:40'),(90,'home',4,5,'[]',1,'2026-03-13 09:34:40','2026-03-13 09:34:40'),(91,'home',5,6,'[]',1,'2026-03-13 09:34:40','2026-03-13 09:34:40');
